import { Link } from 'react-router-dom';
import { ArrowRight, Globe, Gamepad2, Palette, Zap, Shield, Users, Star, Quote, Code2, Layers, Sparkles } from 'lucide-react';
import { useEffect, useRef, useState, useCallback } from 'react';

/* ══════════════════════════════════════════════
   FLOATING PARTICLE FIELD  (canvas, hero bg)
══════════════════════════════════════════════ */
function ParticleField() {
  const ref = useRef(null);
  useEffect(() => {
    const canvas = ref.current;
    const ctx = canvas.getContext('2d');
    let W, H, particles, raf;
    const resize = () => {
      W = canvas.width  = canvas.offsetWidth;
      H = canvas.height = canvas.offsetHeight;
    };
    const make = () => Array.from({ length: 72 }, () => ({
      x: Math.random() * W, y: Math.random() * H,
      r: Math.random() * 1.8 + 0.4,
      vx: (Math.random() - 0.5) * 0.28,
      vy: (Math.random() - 0.5) * 0.28,
      a: Math.random() * 0.5 + 0.1,
    }));
    resize(); particles = make();
    window.addEventListener('resize', () => { resize(); particles = make(); });
    const draw = () => {
      ctx.clearRect(0, 0, W, H);
      particles.forEach(p => {
        p.x += p.vx; p.y += p.vy;
        if (p.x < 0) p.x = W; if (p.x > W) p.x = 0;
        if (p.y < 0) p.y = H; if (p.y > H) p.y = 0;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(90,168,255,${p.a})`;
        ctx.fill();
      });
      // Draw connecting lines
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 110) {
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(0,87,255,${0.12 * (1 - dist / 110)})`;
            ctx.lineWidth = 0.7;
            ctx.stroke();
          }
        }
      }
      raf = requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(raf); window.removeEventListener('resize', resize); };
  }, []);
  return <canvas ref={ref} style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', pointerEvents: 'none' }} />;
}

/* ══════════════════════════════════════════════
   MAGNETIC CURSOR BLOB
══════════════════════════════════════════════ */
function MagneticCursor() {
  const ref = useRef(null);
  const pos = useRef({ x: -200, y: -200 });
  const raf = useRef(null);
  useEffect(() => {
    const onMove = e => { pos.current = { x: e.clientX, y: e.clientY }; };
    window.addEventListener('mousemove', onMove);
    const animate = () => {
      if (ref.current) {
        ref.current.style.left = pos.current.x + 'px';
        ref.current.style.top  = pos.current.y  + 'px';
      }
      raf.current = requestAnimationFrame(animate);
    };
    animate();
    return () => { cancelAnimationFrame(raf.current); window.removeEventListener('mousemove', onMove); };
  }, []);
  return (
    <div ref={ref} style={{
      position: 'fixed', pointerEvents: 'none', zIndex: 9998,
      width: 24, height: 24, borderRadius: '50%',
      background: 'rgba(0,87,255,0.25)',
      border: '1.5px solid rgba(0,87,255,0.7)',
      transform: 'translate(-50%,-50%)',
      transition: 'width 0.3s, height 0.3s, background 0.3s',
      mixBlendMode: 'screen',
    }} id="mag-cursor" />
  );
}

/* ══════════════════════════════════════════════
   SCROLL-DRIVEN COUNTER
══════════════════════════════════════════════ */
function Counter({ end, suffix = '' }) {
  const [v, setV] = useState(0);
  const ref = useRef(null);
  const started = useRef(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => {
      if (e.isIntersecting && !started.current) {
        started.current = true;
        let c = 0; const step = end / 70;
        const t = setInterval(() => { c += step; if (c >= end) { setV(end); clearInterval(t); } else setV(Math.floor(c)); }, 18);
      }
    }, { threshold: 0.4 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, [end]);
  return <span ref={ref}>{v}{suffix}</span>;
}

/* ══════════════════════════════════════════════
   SCROLL-REVEAL WRAPPER  (clip + fade + slide)
══════════════════════════════════════════════ */
function Reveal({ children, delay = 0, dir = 'up', style = {} }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.1 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, []);
  const from = { up: 'translateY(40px)', left: 'translateX(-40px)', right: 'translateX(40px)', scale: 'scale(0.9)' };
  return (
    <div ref={ref} style={{
      opacity: vis ? 1 : 0,
      transform: vis ? 'none' : (from[dir] || from.up),
      transition: `opacity 0.75s cubic-bezier(0.16,1,0.3,1) ${delay}s, transform 0.75s cubic-bezier(0.16,1,0.3,1) ${delay}s`,
      ...style,
    }}>{children}</div>
  );
}

/* ══════════════════════════════════════════════
   3D TILT CARD
══════════════════════════════════════════════ */
function TiltCard({ children, style = {} }) {
  const ref = useRef(null);
  return (
    <div ref={ref} style={{ transition: 'transform 0.15s ease, box-shadow 0.15s ease', ...style }}
      onMouseMove={e => {
        const r = ref.current.getBoundingClientRect();
        const x = (e.clientX - r.left) / r.width  - 0.5;
        const y = (e.clientY - r.top)  / r.height - 0.5;
        ref.current.style.transform = `perspective(800px) rotateY(${x * 12}deg) rotateX(${-y * 8}deg) scale(1.02)`;
      }}
      onMouseLeave={() => { ref.current.style.transform = ''; }}
    >{children}</div>
  );
}

/* ══════════════════════════════════════════════
   WORD-BY-WORD REVEAL TITLE
══════════════════════════════════════════════ */
function WordReveal({ text, style = {}, colorWords = {} }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.2 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, []);
  return (
    <div ref={ref} style={style}>
      {text.split(' ').map((word, i) => (
        <span key={i} style={{
          display: 'inline-block', marginRight: '0.28em',
          color: colorWords[word] || 'inherit',
          fontStyle: colorWords[word] ? 'italic' : 'normal',
          opacity: vis ? 1 : 0,
          transform: vis ? 'translateY(0) rotate(0)' : 'translateY(60%) rotate(3deg)',
          transition: `opacity 0.65s cubic-bezier(0.16,1,0.3,1) ${i * 0.07}s, transform 0.65s cubic-bezier(0.16,1,0.3,1) ${i * 0.07}s`,
        }}>{word}</span>
      ))}
    </div>
  );
}

/* ══════════════════════════════════════════════
   HORIZONTAL SCROLL STRIP (work + stack)
══════════════════════════════════════════════ */
function HScroll({ children, speed = 40 }) {
  const wrapRef = useRef(null);
  const [tx, setTx] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      if (!wrapRef.current) return;
      const rect  = wrapRef.current.getBoundingClientRect();
      const enter = 1 - rect.top / window.innerHeight;
      setTx(Math.min(speed, Math.max(0, (enter - 0.2) * speed * 1.4)));
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener('scroll', onScroll);
  }, [speed]);
  return (
    <div ref={wrapRef} style={{ overflow: 'hidden' }}>
      <div style={{ display: 'flex', gap: 20, width: 'max-content', padding: '0 32px', transform: `translateX(-${tx}%)`, transition: 'transform 0.06s linear', willChange: 'transform' }}>
        {children}
      </div>
    </div>
  );
}

