/* ══════════════════════════════════════════════
   STICKY HERO  — scroll-driven morph
══════════════════════════════════════════════ */
function StickyHero() {
  const wrapRef  = useRef(null);
  const [prog, setProg] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      if (!wrapRef.current) return;
      const rect  = wrapRef.current.getBoundingClientRect();
      const total = rect.height - window.innerHeight;
      setProg(Math.min(1, Math.max(0, -rect.top / total)));
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const imgScale   = 1.18 - prog * 0.18;
  const imgOpacity = 0.12 + prog * 0.2;
  const textY      = prog * -60;
  const textScale  = 1 - prog * 0.08;
  const textOpacity = 1 - prog * 1.4;
  const glowSize   = 700 + prog * 400;
  const lineW      = prog * 100;

  return (
    <div ref={wrapRef} style={{ height: '250vh', position: 'relative' }}>
      <section style={{ position: 'sticky', top: 0, height: '100vh', overflow: 'hidden', background: '#040b18', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        {/* Particle field */}
        <ParticleField />

        {/* Parallax bg image — zooms out as you scroll */}
        <img src="https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=1800&q=75" alt="" aria-hidden style={{ position: 'absolute', inset: 0, width: '100%', height: '120%', objectFit: 'cover', opacity: imgOpacity, transform: `scale(${imgScale})`, willChange: 'transform, opacity', transition: 'none' }} />

        {/* Gradient */}
        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(160deg,rgba(4,11,24,0.97) 0%,rgba(0,30,90,0.82) 50%,rgba(4,11,24,0.97) 100%)' }} />

        {/* Expanding glow orb */}
        <div style={{ position: 'absolute', top: '40%', left: '50%', transform: 'translate(-50%,-50%)', width: glowSize, height: glowSize, borderRadius: '50%', background: 'radial-gradient(circle,rgba(0,87,255,0.09) 0%,transparent 70%)', pointerEvents: 'none', transition: 'none' }} />

        {/* Horizontal line that draws as you scroll */}
        <div style={{ position: 'absolute', bottom: 80, left: '50%', transform: 'translateX(-50%)', height: 1, width: `${lineW}%`, maxWidth: 400, background: 'linear-gradient(to right, transparent, rgba(0,87,255,0.7), transparent)', transition: 'none' }} />

        {/* Main content — rises and fades on scroll */}
        <div className="wrap" style={{ position: 'relative', zIndex: 1, textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '0 20px', transform: `translateY(${textY}px) scale(${textScale})`, opacity: textOpacity, willChange: 'transform, opacity', transition: 'none' }}>

          {/* Status badge */}
          <div style={{ display: 'inline-flex', alignItems: 'center', gap: 8, padding: '7px 18px', background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: 999, fontSize: '0.76rem', fontWeight: 600, color: 'rgba(255,255,255,0.7)', marginBottom: 36, backdropFilter: 'blur(8px)', animation: 'heroIn 0.9s cubic-bezier(0.16,1,0.3,1) both' }}>
            <span style={{ width: 7, height: 7, borderRadius: '50%', background: '#4ade80', boxShadow: '0 0 10px #4ade80', display: 'inline-block' }} />
            Full Stack &amp; Game Development Studio
          </div>

          {/* Headline — words animate in staggered */}
          <h1 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(3rem,8vw,6.5rem)', fontWeight: 900, color: '#fff', lineHeight: 1.03, letterSpacing: '-0.035em', marginBottom: 28, maxWidth: 900 }}>
            {'We Build,'.split(' ').map((w, i) => (
              <span key={i} style={{ display: 'inline-block', marginRight: '0.22em', animation: `heroWord 0.9s cubic-bezier(0.16,1,0.3,1) ${0.1 + i * 0.12}s both` }}>{w}</span>
            ))}
            {' '}
            <em style={{ fontStyle: 'italic', color: '#5aa8ff' }}>
              {'You Grow.'.split(' ').map((w, i) => (
                <span key={i} style={{ display: 'inline-block', marginRight: '0.22em', animation: `heroWord 0.9s cubic-bezier(0.16,1,0.3,1) ${0.3 + i * 0.12}s both` }}>{w}</span>
              ))}
            </em>
          </h1>

          <p style={{ fontSize: 'clamp(0.95rem,1.8vw,1.15rem)', color: 'rgba(255,255,255,0.6)', maxWidth: 580, lineHeight: 1.9, marginBottom: 48, animation: 'heroIn 0.9s 0.6s cubic-bezier(0.16,1,0.3,1) both' }}>
            Synnoviq Technologies delivers scalable Full Stack applications and immersive Game experiences — engineered with precision, driven by innovation.
          </p>

          <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap', justifyContent: 'center', marginBottom: 60, animation: 'heroIn 0.9s 0.75s cubic-bezier(0.16,1,0.3,1) both' }}>
            <Link to="/services" style={{ display:'inline-flex', alignItems:'center', gap:8, padding:'14px 30px', borderRadius:12, background:'#0057ff', color:'#fff', fontWeight:700, fontSize:'0.92rem', boxShadow:'0 6px 24px rgba(0,87,255,0.45)', transition:'all 0.2s ease' }}
              onMouseEnter={e => { e.currentTarget.style.transform='translateY(-3px)'; e.currentTarget.style.boxShadow='0 12px 32px rgba(0,87,255,0.6)'; }}
              onMouseLeave={e => { e.currentTarget.style.transform=''; e.currentTarget.style.boxShadow='0 6px 24px rgba(0,87,255,0.45)'; }}
            >Explore Services <ArrowRight size={16}/></Link>
            <Link to="/contact" style={{ display:'inline-flex', alignItems:'center', gap:8, padding:'14px 30px', borderRadius:12, background:'rgba(255,255,255,0.07)', color:'#fff', fontWeight:700, fontSize:'0.92rem', border:'1px solid rgba(255,255,255,0.12)', backdropFilter:'blur(8px)', transition:'all 0.2s ease' }}
              onMouseEnter={e => { e.currentTarget.style.background='rgba(255,255,255,0.14)'; }}
              onMouseLeave={e => { e.currentTarget.style.background='rgba(255,255,255,0.07)'; }}
            >Let's Talk</Link>
          </div>

          {/* Stack pills */}
          <div style={{ display:'flex', flexWrap:'wrap', gap:8, justifyContent:'center', animation:'heroIn 0.9s 0.9s cubic-bezier(0.16,1,0.3,1) both' }}>
            <span style={{ fontSize:'0.68rem', color:'rgba(255,255,255,0.28)', letterSpacing:'0.12em', textTransform:'uppercase', display:'flex', alignItems:'center', marginRight:4 }}>Stack</span>
            {STACK.slice(0,8).map(t => (
              <span key={t} style={{ padding:'5px 13px', background:'rgba(255,255,255,0.05)', border:'1px solid rgba(255,255,255,0.09)', borderRadius:999, fontSize:'0.74rem', color:'rgba(255,255,255,0.55)', fontWeight:500 }}>{t}</span>
            ))}
          </div>
        </div>

        {/* Scroll cue */}
        <div style={{ position:'absolute', bottom:32, left:'50%', transform:'translateX(-50%)', display:'flex', flexDirection:'column', alignItems:'center', gap:6, opacity: Math.max(0, 1 - prog * 5), transition:'none' }}>
          <span style={{ fontSize:'0.6rem', color:'#fff', letterSpacing:'0.2em', textTransform:'uppercase' }}>Scroll</span>
          <div style={{ width:1, height:36, background:'linear-gradient(to bottom,rgba(255,255,255,0.5),transparent)' }} />
        </div>
      </section>
    </div>
  );
}

