/* ══════════════════════════════════════════════
   PROCESS  — sticky scroll-driven timeline
══════════════════════════════════════════════ */
function ProcessSection() {
  const wrapRef = useRef(null);
  const [prog, setProg] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      if (!wrapRef.current) return;
      const rect  = wrapRef.current.getBoundingClientRect();
      const total = rect.height - window.innerHeight;
      setProg(Math.min(1, Math.max(0, -rect.top / total)));
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Which step is active (0-4) based on progress
  const activeIdx = Math.min(PROCESS.length - 1, Math.floor(prog * PROCESS.length));

  return (
    <div ref={wrapRef} style={{ height:`${100 + PROCESS.length * 80}vh`, position:'relative', background:'#f8f9fc' }}>
      <div style={{ position:'sticky', top:0, height:'100vh', overflow:'hidden', display:'flex', alignItems:'center' }}>
        <div className="wrap" style={{ width:'100%' }}>
          <div style={{ display:'grid', gridTemplateColumns:'1fr', gap:40 }} className="process-split">

            {/* Left: step list */}
            <div>
              <Reveal><span style={{ fontSize:'0.68rem', fontWeight:700, letterSpacing:'0.18em', textTransform:'uppercase', color:'var(--ink20)', display:'block', marginBottom:8 }}>How We Work</span></Reveal>
              <Reveal delay={0.1}><h2 style={{ fontFamily:'var(--serif)', fontSize:'clamp(1.8rem,4vw,3rem)', fontWeight:900, color:'var(--ink)', letterSpacing:'-0.025em', marginBottom:36, lineHeight:1.1 }}>Our Proven Process</h2></Reveal>
              <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
                {PROCESS.map(({ n, Icon, title }, i) => (
                  <div key={n} style={{
                    display:'flex', alignItems:'center', gap:14, padding:'14px 18px', borderRadius:14, cursor:'default',
                    background: activeIdx===i ? 'var(--white)' : 'transparent',
                    border: activeIdx===i ? '1px solid var(--rule)' : '1px solid transparent',
                    boxShadow: activeIdx===i ? '0 4px 20px rgba(0,0,0,0.06)' : 'none',
                    transition: 'all 0.4s cubic-bezier(0.16,1,0.3,1)',
                    transform: activeIdx===i ? 'translateX(8px)' : 'translateX(0)',
                  }}>
                    <div style={{ width:38, height:38, borderRadius:10, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center', background: activeIdx===i ? '#0057ff' : 'var(--rule)', color: activeIdx===i ? '#fff' : 'var(--ink40)', transition:'all 0.4s' }}>
                      <Icon size={16} />
                    </div>
                    <div>
                      <span style={{ fontSize:'0.62rem', fontWeight:700, letterSpacing:'0.12em', textTransform:'uppercase', color: activeIdx===i ? '#0057ff' : 'var(--ink20)', display:'block', marginBottom:1 }}>Step {n}</span>
                      <strong style={{ fontSize:'0.95rem', color: activeIdx===i ? 'var(--ink)' : 'var(--ink40)', fontWeight:700 }}>{title}</strong>
                    </div>
                    {activeIdx===i && <div style={{ marginLeft:'auto', width:8, height:8, borderRadius:'50%', background:'#0057ff' }} />}
                  </div>
                ))}
              </div>
            </div>

            {/* Right: detail card */}
            <div style={{ display:'flex', alignItems:'center' }}>
              <div style={{ background:'var(--white)', border:'1px solid var(--rule)', borderRadius:24, padding:'44px 40px', boxShadow:'0 8px 40px rgba(0,0,0,0.07)', width:'100%' }}>
                {(() => {
                  const { n, Icon, title, desc } = PROCESS[activeIdx];
                  return (
                    <>
                      <div style={{ display:'flex', alignItems:'center', gap:16, marginBottom:28 }}>
                        <div style={{ width:56, height:56, borderRadius:14, background:'#0057ff', display:'flex', alignItems:'center', justifyContent:'center', color:'#fff', boxShadow:'0 8px 24px rgba(0,87,255,0.35)', flexShrink:0 }}><Icon size={24} /></div>
                        <div>
                          <span style={{ fontSize:'0.62rem', fontWeight:700, letterSpacing:'0.16em', textTransform:'uppercase', color:'#0057ff', display:'block' }}>Step {n}</span>
                          <h3 style={{ fontFamily:'var(--serif)', fontSize:'1.8rem', fontWeight:900, color:'var(--ink)', lineHeight:1.1 }}>{title}</h3>
                        </div>
                      </div>
                      <p style={{ fontSize:'1.02rem', color:'var(--ink60)', lineHeight:1.9, marginBottom:32 }}>{desc}</p>
                      {/* Progress dots */}
                      <div style={{ display:'flex', gap:7 }}>
                        {PROCESS.map((_, pi) => (
                          <div key={pi} style={{ height:4, borderRadius:2, transition:'all 0.4s cubic-bezier(0.16,1,0.3,1)', background: pi===activeIdx ? '#0057ff' : 'var(--rule)', width: pi===activeIdx ? 32 : 8 }} />
                        ))}
                      </div>
                    </>
                  );
                })()}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

