      </div>
      <HScroll speed={30}>
        {WORK.map((w, i) => (
          <div key={i} style={{ width:320, flexShrink:0 }}>
            <TiltCard style={{ borderRadius:18, overflow:'hidden', height:240, position:'relative', cursor:'pointer' }}>
              <img src={w.img} alt={w.title} style={{ width:'100%', height:'100%', objectFit:'cover' }} />
              <div style={{ position:'absolute', inset:0, background:'linear-gradient(to top, rgba(4,11,24,0.92) 0%, transparent 55%)' }} />
              <div style={{ position:'absolute', bottom:0, left:0, right:0, padding:'20px' }}>
                <span style={{ fontSize:'0.62rem', fontWeight:700, letterSpacing:'0.14em', textTransform:'uppercase', color:'#5aa8ff', display:'block', marginBottom:4 }}>{w.tag}</span>
                <h4 style={{ fontFamily:'var(--serif)', fontSize:'1.05rem', fontWeight:800, color:'#fff', marginBottom:10 }}>{w.title}</h4>
                <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
                  {w.tech.map(t => <span key={t} style={{ padding:'3px 9px', background:'rgba(255,255,255,0.1)', border:'1px solid rgba(255,255,255,0.15)', borderRadius:999, fontSize:'0.66rem', color:'rgba(255,255,255,0.7)', fontWeight:500 }}>{t}</span>)}
                </div>
              </div>
            </TiltCard>
          </div>
        ))}
      </HScroll>
    </section>
  );
}

