/* ══════════════════════════════════════════════
   TESTIMONIALS  — auto-rotating carousel
══════════════════════════════════════════════ */
function TestimonialsSection() {
  const [active, setActive] = useState(0);
  const [prev, setPrev]     = useState(null);
  useEffect(() => {
    const t = setInterval(() => {
      setActive(a => { setPrev(a); return (a + 1) % TESTIMONIALS.length; });
    }, 4000);
    return () => clearInterval(t);
  }, []);

  return (
    <section style={{ background:'#f4f6fb', padding:'96px 0', borderTop:'1px solid var(--rule)' }}>
      <div className="wrap">
        <Reveal><div style={{ textAlign:'center', marginBottom:52 }}>
          <span className="label">Client Stories</span>
          <WordReveal text="What Our Clients Say" style={{ fontFamily:'var(--serif)', fontSize:'clamp(1.8rem,4vw,3rem)', fontWeight:900, color:'var(--ink)', letterSpacing:'-0.025em' }} colorWords={{ Say:'var(--blue)' }} />
        </div></Reveal>

        <div style={{ maxWidth:680, margin:'0 auto', position:'relative', minHeight:220 }}>
          {TESTIMONIALS.map((t, i) => (
            <div key={i} style={{
              position: i === 0 ? 'relative' : 'absolute',
              top: 0, left: 0, right: 0,
              opacity: active === i ? 1 : 0,
              transform: active === i ? 'translateY(0) scale(1)' : prev === i ? 'translateY(-20px) scale(0.97)' : 'translateY(20px) scale(0.97)',
              transition: 'all 0.6s cubic-bezier(0.16,1,0.3,1)',
              pointerEvents: active === i ? 'auto' : 'none',
            }}>
              <TiltCard style={{ background:'var(--white)', border:'1px solid var(--rule)', borderRadius:24, padding:'40px 44px', boxShadow:'0 8px 40px rgba(0,0,0,0.06)' }}>
                <Quote size={32} style={{ color:'var(--blue)', opacity:0.2, marginBottom:20 }} />
                <p style={{ fontSize:'1.05rem', color:'var(--ink60)', lineHeight:1.9, marginBottom:32, fontStyle:'italic' }}>{t.text}</p>
                <div style={{ display:'flex', alignItems:'center', gap:14 }}>
                  <div style={{ width:46, height:46, borderRadius:'50%', background:'var(--blue)', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:'var(--serif)', fontWeight:900, color:'#fff', fontSize:'1.1rem', flexShrink:0 }}>{t.name[0]}</div>
                  <div>
                    <strong style={{ display:'block', fontSize:'0.92rem', color:'var(--ink)', fontWeight:700 }}>{t.name}</strong>
                    <span style={{ fontSize:'0.74rem', color:'var(--ink20)' }}>{t.role}</span>
                  </div>
                  <div style={{ marginLeft:'auto', display:'flex', gap:3 }}>
                    {[...Array(t.stars)].map((_, s) => <Star key={s} size={13} style={{ color:'#f59e0b', fill:'#f59e0b' }} />)}
                  </div>
                </div>
              </TiltCard>
            </div>
          ))}
        </div>

        {/* Dots */}
        <div style={{ display:'flex', justifyContent:'center', gap:8, marginTop:32 }}>
          {TESTIMONIALS.map((_, i) => (
            <button key={i} onClick={() => { setPrev(active); setActive(i); }} style={{ height:4, borderRadius:2, border:'none', cursor:'pointer', transition:'all 0.4s cubic-bezier(0.16,1,0.3,1)', background: i===active ? 'var(--blue)' : 'var(--rule)', width: i===active ? 32 : 8 }} />
          ))}
        </div>
      </div>
    </section>
  );
}

/* ══════════════════════════════════════════════
   TECH STACK  — horizontal scroll marquee
