              onMouseEnter={e => { e.currentTarget.style.background='var(--blue)'; e.currentTarget.style.color='#fff'; e.currentTarget.style.borderColor='var(--blue)'; e.currentTarget.style.transform='translateY(-2px)'; }}
              onMouseLeave={e => { e.currentTarget.style.background='var(--white)'; e.currentTarget.style.color='var(--ink60)'; e.currentTarget.style.borderColor='var(--rule)'; e.currentTarget.style.transform=''; }}
