/* ══════════════════════════════════════════════
   INTERNSHIP CTA  — parallax dark section
══════════════════════════════════════════════ */
function CtaSection() {
  const ref  = useRef(null);
  const [ty, setTy] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      if (!ref.current) return;
      const rect = ref.current.getBoundingClientRect();
      setTy((window.innerHeight - rect.top) * 0.2);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);
  return (
    <section ref={ref} style={{ background:'#060c18', position:'relative', overflow:'hidden', padding:'100px 0' }}>
      <img src="https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=1600&q=75" alt="" aria-hidden style={{ position:'absolute', inset:0, width:'100%', height:'130%', objectFit:'cover', opacity:.08, transform:`translateY(${ty}px)`, willChange:'transform', transition:'none' }} />
      <div style={{ position:'absolute', inset:0, background:'linear-gradient(135deg,rgba(6,12,24,.97),rgba(0,35,100,.72))' }} />
      <div className="wrap" style={{ position:'relative', zIndex:1 }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', flexWrap:'wrap', gap:40 }}>
          <Reveal dir="left" style={{ maxWidth:600 }}>
            <span style={{ fontSize:'0.68rem', fontWeight:700, letterSpacing:'0.18em', textTransform:'uppercase', color:'rgba(255,255,255,0.4)', display:'block', marginBottom:12 }}>Internship Programme</span>
            <h2 style={{ fontFamily:'var(--serif)', fontSize:'clamp(1.8rem,4vw,3rem)', fontWeight:900, color:'#fff', marginBottom:16, letterSpacing:'-0.025em', lineHeight:1.1 }}>Shape Your Career with Synnoviq</h2>
            <p style={{ fontSize:'0.97rem', color:'rgba(255,255,255,0.5)', lineHeight:1.85 }}>Hands-on, mentor-driven internships tied to real live projects. Passionate about full stack, game dev, or design? We want you.</p>
          </Reveal>
          <Reveal dir="right">
            <Link to="/careers#internships" style={{ display:'inline-flex', alignItems:'center', gap:10, padding:'16px 34px', borderRadius:14, background:'#fff', color:'#040b18', fontSize:'0.95rem', fontWeight:800, boxShadow:'0 4px 24px rgba(255,255,255,0.1)', transition:'all 0.25s ease' }}
              onMouseEnter={e => { e.currentTarget.style.background='#0057ff'; e.currentTarget.style.color='#fff'; e.currentTarget.style.transform='translateY(-3px)'; e.currentTarget.style.boxShadow='0 12px 32px rgba(0,87,255,0.5)'; }}
              onMouseLeave={e => { e.currentTarget.style.background='#fff'; e.currentTarget.style.color='#040b18'; e.currentTarget.style.transform=''; e.currentTarget.style.boxShadow='0 4px 24px rgba(255,255,255,0.1)'; }}
            >Apply Now <ArrowRight size={17} /></Link>
          </Reveal>
        </div>
      </div>
    </section>
  );
}

